class Solution {
    public int findBestValue(int[] arr, int target) {
        int bestValue = Integer.MIN_VALUE;
        int sumDiff = Integer.MAX_VALUE;
        for (int num : arr) {
            int newSum = arr.stream().mapToInt(x -> x - num).sum();
            int diff = Math.abs(newSum - target);
            if (diff < sumDiff) {
                bestValue = num;
                sumDiff = diff;
            }
        }
        return bestValue;
    }
}
